import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { Customer, SalesOrder } from '../../core/models';

/**
 * Sales orders list. New SO opened via `?modal=new` (pick a customer; lines
 * added on the detail page). Mutations gated to sales + admin.
 */
@Component({
  selector: 'app-sales-orders',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './sales-orders.component.html',
  styleUrl: './sales-orders.component.css',
})
export class SalesOrdersComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);
  readonly saving = signal(false);

  readonly customers = signal<Customer[]>([
    { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example' },
    { id: 'c2', name: 'Contoso Ltd', email: 'ap@contoso.example' },
    { id: 'c3', name: 'Fabrikam Inc', email: 'buy@fabrikam.example' },
  ]);

  readonly orders = signal<SalesOrder[]>([
    { id: 'so1', customerId: 'c1', status: 'draft',
      customer: { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example' }, totalCents: 49950 },
    { id: 'so2', customerId: 'c2', status: 'confirmed',
      customer: { id: 'c2', name: 'Contoso Ltd', email: 'ap@contoso.example' }, totalCents: 74970 },
    { id: 'so3', customerId: 'c3', status: 'fulfilled',
      customer: { id: 'c3', name: 'Fabrikam Inc', email: 'buy@fabrikam.example' }, totalCents: 124950 },
    { id: 'so4', customerId: 'c1', status: 'invoiced',
      customer: { id: 'c1', name: 'Northwind Traders', email: 'orders@northwind.example' }, totalCents: 29970 },
  ]);

  readonly canEdit = computed(() => this.auth.isSales());

  readonly modalOpen = signal(false);
  form = { customerId: '' };

  constructor(
    public auth: AuthService,
    private route: ActivatedRoute,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.route.queryParams.subscribe((q) => {
      this.modalOpen.set(q['modal'] === 'new' && this.canEdit());
      if (this.modalOpen()) this.form = { customerId: this.customers()[0]?.id ?? '' };
    });
  }

  money(cents: number | undefined): string {
    return ((cents ?? 0) / 100).toLocaleString(undefined, { style: 'currency', currency: 'USD' });
  }

  statusClass(s: string): string {
    return s === 'invoiced' ? 'badge-brand'
      : s === 'fulfilled' ? 'badge-ok'
      : s === 'confirmed' ? 'badge-info'
      : 'badge-muted';
  }

  close(): void {
    this.router.navigate([], { queryParams: {} });
    this.modalOpen.set(false);
  }

  create(): void {
    if (!this.form.customerId) {
      this.error.set('Choose a customer.');
      return;
    }
    this.saving.set(true);
    const cust = this.customers().find((c) => c.id === this.form.customerId) ?? null;
    const id = 'so' + (this.orders().length + 1);
    this.orders.update((list) => [
      { id, customerId: this.form.customerId, status: 'draft', customer: cust, totalCents: 0 },
      ...list,
    ]);
    this.saving.set(false);
    this.modalOpen.set(false);
    this.router.navigate(['/sales-orders', id]);
  }
}
